package Operators;

public class Unaryoperator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int a=10;
		System.out.println(a++);
		System.out.println(--a);
		System.out.println(a--);
		System.out.println(++a);
		
		int b=10;
		System.out.println(a++);
		System.out.println(++a);
		System.out.println(a--);
		System.out.println(--a);



	}

}
//10
//10
//10
//10
//10
//12
//12
//10
